from opentelemetry import metrics
from dataclasses import dataclass


meter = metrics.get_meter("genai-service")

rate_limit_utilisation = meter.create_gauge(
    "genai_provider_rate_limit_utilisation_ratio",
    description="Fraction of provider token-per-minute rate limit consumed (0.0–1.0)",
)

context_utilisation = meter.create_histogram(
    "genai_chat_context_utilisation_ratio",
    description="Fraction of max context window used by the prompt (0.0–1.0)",
)

gpu_vram_utilisation = meter.create_gauge(
    "genai_inference_gpu_vram_utilisation_ratio",
    description="GPU VRAM utilisation for self-hosted inference pods (0.0–1.0)",
)


@dataclass
class RateLimitTracker:
    tokens_per_minute_limit: int
    window_tokens_used: int = 0

    @property
    def utilisation(self) -> float:
        return self.window_tokens_used / self.tokens_per_minute_limit

    def record(self, model: str, provider: str, env: str) -> None:
        rate_limit_utilisation.set(
            self.utilisation,
            {"model": model, "provider": provider, "env": env}
        )

    def add_tokens(self, count: int) -> None:
        self.window_tokens_used += count

    def reset_window(self) -> None:
        self.window_tokens_used = 0


def record_context_saturation(
    prompt_tokens: int,
    max_context_tokens: int,
    model: str,
    provider: str,
    env: str,
) -> None:
    ratio = prompt_tokens / max_context_tokens
    context_utilisation.record(ratio, {
        "model": model, "provider": provider, "env": env
    })
